import itertools
import random

def calculate_probability(coins, n):
    probability = 0
    for combination in itertools.combinations(coins, n):
        combination_probability = 1
        for coin in combination:
            combination_probability *= coin
        for coin in coins:
            if coin not in combination:
                combination_probability *= (1 - coin)
        probability += combination_probability
    return probability

def generate_coins(n):
    coins = []
    for _ in range(2 * n):
        coins.append(random.random())
    return coins

