    max_probability = 0
    best_combination = None
    for combination in itertools.combinations(coins, n):
        combination_probability = 1
        for coin in combination:
            combination_probability *= coin
        for coin in coins:
            if coin not in combination:
                combination_probability *= (1 - coin)
        if combination_probability > max_probability:
            max_probability = combination_probability
            best_combination = combination
    return best_combination, max_probability

