import itertools
import random

def calculate_probability(coins, n):
    total_probability = 0
    for combination in itertools.combinations(coins, n):
        probability = 1
        for coin in combination:
            probability *= coin
        for coin in set(coins) - set(combination):
            probability *= (1 - coin)
        total_probability += probability
    return total_probability

def brute_force(coins, n):
    max_probability = 0
    best_combination = None
    for combination in itertools.combinations(coins, n):
        probability = 1
        for coin in combination:
            probability *= coin
        for coin in set(coins) - set(combination):
            probability *= (1 - coin)
        if probability > max_probability:
            max_probability = probability
            best_combination = combination
    return best_combination, max_probability

def greedy(coins, n):
    coins.sort(reverse=True)
    combination = coins[:n]
    probability = 1
    for coin in combination:
        probability *= coin
    for coin in coins[n:]:
        probability *= (1 - coin)
    return combination, probability

def main():
    n = 5
    coins = [random.random() for _ in range(2 * n)]
    print("Coins:", coins)

    combination_brute, probability_brute = brute_force(coins, n)
    print("Brute Force Combination:", combination_brute)
    print("Brute Force Probability:", probability_brute)

    combination_greedy, probability_greedy = greedy(coins, n)
    print("Greedy Combination:", combination_greedy)
    print("Greedy Probability:", probability_greedy)

if __name__ == "__main__":
    main()

