import itertools
import numpy as np

def calculate_probability(coins, p_values):
    probability = 1
    for i in range(len(coins)):
        if coins[i] == 1:
            probability *= p_values[i]
        else:
            probability *= (1 - p_values[i])
    return probability

def brute_force(coins, p_values, n):
    max_probability = 0
    best_set = None
    for r in range(len(coins) + 1):
        for combination in itertools.combinations(range(len(coins)), r):
            coins_copy = [0] * len(coins)
            for i in combination:
                coins_copy[i] = 1
            if sum(coins_copy) == n:
                probability = calculate_probability(coins_copy, p_values)
                if probability > max_probability:
                    max_probability = probability
                    best_set = coins_copy
    return best_set, max_probability

def dynamic_programming(coins, p_values, n):
    dp = [[0] * (n + 1) for _ in range(len(coins) + 1)]
    for i in range(len(coins) + 1):
        dp[i][0] = 1
    for i in range(1, len(coins) + 1):
        for j in range(1, n + 1):
            dp[i][j] = dp[i - 1][j]
            if j >= 1:
                dp[i][j] += dp[i - 1][j - 1] * p_values[i - 1]
    max_probability = 0
    best_set = None
    for i in range(len(coins) + 1):
        for j in range(n + 1):
            if dp[i][j] > max_probability and j == n:
                max_probability = dp[i][j]
                best_set = [1] * j + [0] * (i - j)
    return best_set, max_probability

def greedy(coins, p_values, n):
    sorted_p_values = sorted(p_values, reverse=True)
    best_set = [0] * len(coins)
    for i in range(n):
        best_set[p_values.index(sorted_p_values[i])] = 1
    return best_set, calculate_probability(best_set, p_values)

coins = [0] * 10
p_values = np.random.rand(10)
n = 5

best_set_brute_force, max_probability_brute_force = brute_force(coins, p_values, n)
best_set_dynamic_programming, max_probability_dynamic_programming = dynamic_programming(coins, p_values, n)
