    max_prob = 0
    best_set = None
    for subset in itertools.combinations(coins, n):
        prob = 1
        for p in subset:
            prob *= p
        for p in [c for c in coins if c not in subset]:
            prob *= (1 - p)
        if prob > max_prob:
            max_prob = prob
            best_set = subset
    return best_set, max_prob

def method2_greedy(coins, n):
    coins.sort(reverse=True)
    subset = coins[:n]
    prob = 1
    for p in subset:
        prob *= p
    for p in coins[n:]:
        prob *= (1 - p)
    return subset, prob

def method3_dynamic_programming(coins, n):
    dp = [[0.0] * (n + 1) for _ in range(len(coins) + 1)]
    dp[0][0] = 1.0
    for i in range(1, len(coins) + 1):
        for j in range(min(i, n) + 1):
            if j == 0:
                dp[i][j] = dp[i - 1][j] * (1 - coins[i - 1])
            else:
                dp[i][j] = dp[i - 1][j - 1] * coins[i - 1] + dp[i - 1][j] * (1 - coins[i - 1])
