class Coin:
    def __init__(self, probability):
        self.probability = probability

def generate_coins(n):
    coins = []
    for i in range(2*n):
        coins.append(Coin((i+1)/(2*n)))
    return coins

def brute_force(coins, n):
    max_probability = 0
    best_set = None
    for i in range(1 << len(coins)):
        set_coins = [coins[j] for j in range(len(coins)) if (i & (1 << j))]
        if len(set_coins) == n:
            probability = 1
            for coin in set_coins:
                probability *= coin.probability
            for coin in coins:
                if coin not in set_coins:
                    probability *= (1-coin.probability)
            if probability > max_probability:
                max_probability = probability
                best_set = set_coins
    return best_set, max_probability

def dynamic_programming(coins, n):
    dp = [[0]*(n+1) for _ in range(len(coins)+1)]
    for i in range(1, len(coins)+1):
        for j in range(1, min(i, n)+1):
            dp[i][j] = max(dp[i-1][j], dp[i-1][j-1] + coins[i-1].probability)
    best_set = []
    i, j = len(coins), n
    while j > 0:
        if dp[i][j] != dp[i-1][j]:
            best_set.append(coins[i-1])
            j -= 1
        i -= 1
    return best_set, dp[-1][-1]

def greedy(coins, n):
    coins.sort(key=lambda x: x.probability, reverse=True)
    best_set = coins[:n]
    probability = 1
    for coin in best_set:
        probability *= coin.probability
    for coin in coins:
        if coin not in best_set:
            probability *= (1-coin.probability)
    return best_set, probability

