def generate_coins(n):
    coins = []
    for i in range(1, n+1):
        coins.append((i, 1/i))
    return coins

def calculate_probability(coins, n):
    probability = 0
    for combination in itertools.combinations(coins, n):
        prob = 1
        for coin in combination:
            prob *= coin[1]
        for coin in coins:
            if coin not in combination:
                prob *= (1 - coin[1])
        probability += prob
    return probability

def find_best_set(coins, n):
    best_set = None
    best_probability = 0
    for combination in itertools.combinations(coins, n):
        probability = calculate_probability(list(combination), n)
