    coins.sort(key=lambda x: x[1], reverse=True)
    best_set = []
    for coin in coins:
        if len(best_set) < n:
            best_set.append(coin)
        else:
            break
    return best_set, calculate_probability(best_set, n)

def simulated_annealing(coins, n, iterations=1000, temperature=100):
    best_set = random.sample(coins, n)
    best_probability = calculate_probability(best_set, n)
    for _ in range(iterations):
        temperature *= 0.99
        new_set = best_set.copy()
        i = random.randint(0, n-1)
        j = random.randint(0, len(coins)-1)
        if coins[j] not in new_set:
            new_set[i] = coins[j]
        new_probability = calculate_probability(new_set, n)
        if new_probability > best_probability:
            best_probability = new_probability
            best_set = new_set
        elif random.random() < (new_probability - best_probability) / temperature:
            best_set = new_set
    return best_set, best_probability

